import{_ as a,o as e,c as d,ag as r}from"./chunks/framework.f_9xDHrT.js";const p=JSON.parse('{"title":"出海垂钓","description":"MissFisher 的出海垂钓模式与航线预报说明。","frontmatter":{"title":"出海垂钓","description":"MissFisher 的出海垂钓模式与航线预报说明。"},"headers":[],"relativePath":"manual/scenarios/ocean.md","filePath":"manual/scenarios/ocean.md","lastUpdated":null}'),o={name:"manual/scenarios/ocean.md"};function i(s,t,n,l,h,b){return e(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="出海垂钓" tabindex="-1">出海垂钓 <a class="header-anchor" href="#出海垂钓" aria-label="Permalink to &quot;出海垂钓&quot;">​</a></h1><h2 id="模式" tabindex="-1">模式 <a class="header-anchor" href="#模式" aria-label="Permalink to &quot;模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>主要目的</th><th>备注</th></tr></thead><tbody><tr><td><em>冲分</em></td><td>称号【海王】【世界级钓手】</td><td>渔分的高低比较看运气</td></tr><tr><td><em>蓝鱼</em></td><td>点亮蓝色稀有度鱼类的图鉴</td><td>会尝试钓航线中所有可钓的蓝鱼，当已无蓝鱼可钓时将使用冲分手法</td></tr><tr><td><em>种类x</em></td><td>航线预报中角标x对应的数量类成就&amp;称号</td><td>请留意选择的模式<br>部分数量类成就需要组队才能完成</td></tr><tr><td><em>练级</em></td><td>在出海垂钓中提升等级</td><td>如果你已完成 6.x 版本的主线任务且喜欢折腾<br>请尝试 <a href="https://nga.178.com/read.php?tid=45353336" target="_blank" rel="noreferrer">在宇宙探索练级</a></td></tr><tr><td><em>耐力xx</em></td><td>全自动地完成海钓循环</td><td>现支持：冲分/蓝鱼/练级</td></tr></tbody></table><h2 id="启动" tabindex="-1">启动 <a class="header-anchor" href="#启动" aria-label="Permalink to &quot;启动&quot;">​</a></h2><p>切换到带 <code>耐力</code> 前缀的模式，点击启动按钮即可。</p><h2 id="航线预报" tabindex="-1">航线预报 <a class="header-anchor" href="#航线预报" aria-label="Permalink to &quot;航线预报&quot;">​</a></h2><p>你可以在主界面选择 <code>航线</code> 页签查看航线预报。</p><p>一组航线预报由 2 行内容组成：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>11-02 02:00　「索蒂斯（火萤）」「依拉丝莫龙（重铁板钩）」　梅尔托尔海峡南(昏)》加拉迪翁湾(夜)》梅尔托尔海峡北(日)　04</span></span>
<span class="line"><span>　　　　　　　「四海大宝贝¹」「塔尼瓦（青花鱼块）」　　　　 妖歌海海面(日)》黄金港近海(昏)》无二江下游(夜)</span></span></code></pre></div><ul><li>第 1 行是近海航线，第 2 行是远海航线。</li><li>每列从左到右分别是：开放登记时间、航线标识、海域与时间带、在 MissFisher 的内部序号。</li></ul><h3 id="航线预报中的航线标识" tabindex="-1">航线预报中的航线标识 <a class="header-anchor" href="#航线预报中的航线标识" aria-label="Permalink to &quot;航线预报中的航线标识&quot;">​</a></h3><p>航线预报中的航线标识灵感和顺序来自 <a href="https://fish.ffmomola.com/ng/#/oceanFishing" target="_blank" rel="noreferrer">鱼糕-出海垂钓航线</a>。</p><table tabindex="0"><thead><tr><th>类型</th><th>标识</th><th>备注</th></tr></thead><tbody><tr><td>渔分</td><td>「挑战高分」</td><td>渔分上限较高，也适合获取「海王」称号&amp;成就；<br>全自动下少数情况能获得 3~4 万分的高分；<br>运气差时可能只有几千。</td></tr><tr><td>远洋<br>渔分</td><td>「深洋之劫」</td><td>适合获取「深洋之劫」称号&amp;成就的远洋航线</td></tr><tr><td>渔分</td><td>「世界级钓手」</td><td>分数下限较高；<br>适合获取「世界级钓手」称号&amp;成就的航线。</td></tr><tr><td>近海<br>蓝鱼</td><td>「盾齿龙」<br>「海洋蟾蜍（潮虫）」<br>「依拉丝莫龙（重铁板钩）」<br>「哈弗古法（乌贼丝）」<br>「珊瑚蝠鲼（小虾肉笼）」<br>「索蒂斯（火萤）」<br>「石骨鱼（沟鼠尾巴）」</td><td>圆括号中是需要额外携带的钓饵</td></tr><tr><td>远洋<br>蓝鱼</td><td>「琉璃龙」<br>「狱之蟹（乌贼丝）」<br>「塔尼瓦（青花鱼块）」<br>「梅泉宝龟（石蝇幼虫）」</td><td>圆括号中是需要额外携带的钓饵</td></tr><tr><td>近海<br>数量类<br>成就</td><td>「水母狂魔¹」<br>「横路不通¹」<br>「只有我最鳐摆²」<br>「捕鲨人¹」<br>「龙马惊神¹」<br>「只有我最鳐摆¹」<br>「气鲀四海¹」<br>「八爪旅人¹」</td><td>角标 <code>¹</code> <code>²</code>：<br>表示需求为该标识时应使用的种类模式<br><code>¹</code> = 种类1<br><code>²</code> = 种类2</td></tr><tr><td>远洋<br>数量类<br>成就</td><td>「大虾可重新来过²」<br>「大虾可重新来过¹」<br>「四海大宝贝¹」<br>「鱿型中队精英¹」</td><td>角标 <code>¹</code> <code>²</code>：<br>表示需求为该标识时应使用的种类模式<br><code>¹</code> = 种类1<br><code>²</code> = 种类2</td></tr></tbody></table><h2 id="特定鱼类" tabindex="-1">特定鱼类 <a class="header-anchor" href="#特定鱼类" aria-label="Permalink to &quot;特定鱼类&quot;">​</a></h2><ul><li>非幻海流的绿色稀有度鱼类，需要你在对应海域和时机手动启动对应预设。</li><li>具体目标可继续看 <a href="./fish">钓特定鱼类</a>。</li></ul>`,15)])])}const m=a(o,[["render",i]]);export{p as __pageData,m as default};
